-- Part 1: University-level data for University of Southampton
UPDATE public.universities SET
  website_url = 'https://www.southampton.ac.uk',
  tuition_usd = 29700,
  overall_acceptance_rate = '15%',
  test_policy = 'Not applicable',
  deadline_calendar = 'UCAS deadline: January 29 (18:00 GMT) for September entry. Equal consideration given to all applications received by the deadline. No early action or early decision. Deferred entry (gap year) applications accepted. International qualifications assessed on equivalent basis.',
  financial_aid = 'Southampton Undergraduate Scholarship for International Students (merit-based, up to £5,000/year); Vice-Chancellor Scholarship (up to £10,000/year for high-achieving international students); Hampshire County Council Scholarship; subject-specific bursaries in Engineering and Science; UK Home students eligible for government tuition fee loans and means-tested maintenance grants. Scholarships applied for via the university scholarship portal after receiving an offer.'
WHERE name = 'University of Southampton';

-- Part 2: Top 10 majors for University of Southampton
