  ('BSc Computer Science',              '16%', 'A-Level Mathematics required; Computing or Further Mathematics desirable but not essential; personal statement should demonstrate programming experience and genuine interest in computing; strong GCSE profile expected',                                                                              90,  6.5::numeric, 90, NULL::integer, NULL::integer, 3.5::numeric, 'AAB', 33, NULL::numeric, 110, 59),
  ('BEng Mechanical Engineering',       '19%', 'A-Level Mathematics and Physics required; personal statement should show enthusiasm for engineering design and mechanics; strong GCSE profile expected including Mathematics and Physics',                                                                                                              120, 6.5::numeric, 90, NULL::integer, NULL::integer, 3.5::numeric, 'ABB', 32, NULL::numeric, 110, 59),
  ('BSc Physics',                       '22%', 'A-Level Mathematics and Physics required; Further Mathematics desirable; personal statement should demonstrate genuine curiosity for physical sciences and any relevant activities such as astronomy clubs or extended projects',                                                                        85,  6.5::numeric, 90, NULL::integer, NULL::integer, 3.5::numeric, 'AAB', 33, NULL::numeric, 110, 59),
  ('BSc Oceanography',                  '25%', 'A-Level Mathematics and one science (Biology, Chemistry, or Physics) required; personal statement should reflect interest in marine and environmental sciences; Southampton is a world-leading centre for oceanography',                                                                                 8,   6.5::numeric, 90, NULL::integer, NULL::integer, 3.3::numeric, 'ABB', 32, NULL::numeric, 110, 59),
  ('LLB Law',                           '12%', 'No specific A-Level subjects required; essay-based subjects such as History, English, or Politics highly valued; LNAT (Law National Admissions Test) required; personal statement must demonstrate analytical and critical thinking skills and genuine interest in law',                                 90,  6.5::numeric, 90, NULL::integer, NULL::integer, 3.5::numeric, 'AAB', 33, NULL::numeric, 110, 59),
